const raw = $json.filepath;
if (!raw || raw.trim() === '') {
  return [];
}
const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length > 0);
return lines.map(line => {
  // Derive the matching demo account_id from onboarding filename
  const filename = line.split('/').pop().replace('.txt', '');
  const accountId = filename.replace('onboarding_', 'demo_');
  return {
    json: {
      filepath: line,
      onboarding_filename: filename,
      account_id: accountId
    }
  };
});

// v1 MISSING: log warning, continue to next file
const item = $json;
const warning = `⚠️ [Pipeline B] No v1 found for ${item.account_id}. Run Pipeline A first.`;
console.warn(warning);
return [{
  json: {
    account_id: item.account_id,
    filepath: item.filepath,
    status: 'skipped',
    reason: 'v1_not_found',
    message: warning
  }
}];

const stdout = $json.stdout || '';
const stderr = $json.stderr || '';
const exitCode = $json.exitCode;

const changesMatch = stdout.match(/changes_count:\s*(\d+)/);
const accountMatch = stdout.match(/account_id:\s*([\w_]+)/);

return [{
  json: {
    filepath: $json.filepath,
    account_id: accountMatch ? accountMatch[1] : $json.account_id,
    status: exitCode === 0 ? 'success' : 'error',
    changes_count: changesMatch ? parseInt(changesMatch[1]) : 0,
    stdout: stdout,
    stderr: stderr,
    exit_code: exitCode
  }
}];

const item = $json;
console.log(`✓ [Pipeline B] ${item.account_id} → v2 complete | ${item.changes_count} fields updated`);
return [{ json: { ...item, logged_at: new Date().toISOString() } }];

const item = $json;
const fs = require('fs');
const logPath = '/data/logs/errors.jsonl';
const entry = JSON.stringify({
  timestamp: new Date().toISOString(),
  pipeline: 'B',
  filepath: item.filepath,
  account_id: item.account_id,
  exit_code: item.exit_code,
  stderr: item.stderr
}) + '\n';
try {
  fs.mkdirSync('/data/logs', { recursive: true });
  fs.appendFileSync(logPath, entry);
} catch(e) {
  console.error('Could not write error log:', e.message);
}
console.error(`✗ [Pipeline B ERROR] ${item.account_id}: ${item.stderr}`);
return [{ json: { ...item, error_logged: true, status: 'error' } }];

// Collect ALL results (success + error + skipped) for final summary
const allItems = $input.all();
const total = allItems.length;
const succeeded = allItems.filter(i => i.json.status === 'success').length;
const skipped = allItems.filter(i => i.json.status === 'skipped').length;
const failed = allItems.filter(i => i.json.status === 'error').length;
const totalChanges = allItems.reduce((sum, i) => sum + (i.json.changes_count || 0), 0);

console.log(`\n${'='.repeat(50)}`);
console.log(`PIPELINE B COMPLETE`);
console.log(`  Succeeded: ${succeeded}/${total}`);
console.log(`  Skipped (no v1): ${skipped}`);
console.log(`  Failed: ${failed}`);
console.log(`  Total field changes: ${totalChanges}`);
allItems.forEach(item => {
  const icon = item.json.status === 'success' ? '✓' : item.json.status === 'skipped' ? '⚠' : '✗';
  console.log(`  ${icon} ${item.json.account_id} | changes: ${item.json.changes_count || 0}`);
});
console.log('='.repeat(50));

return [{
  json: {
    pipeline: 'B',
    total,
    succeeded,
    skipped,
    failed,
    total_field_changes: totalChanges,
    completed_at: new Date().toISOString()
  }
}];
